//
//  TaskQueue.swift
//  Radiacode
//
//  Created by Matvey Kozin on 27.09.2023.
//

import Foundation

protocol PendingTask: AnyObject {
    var label: String? { get }
    var isCancelled: Bool { get set }

    func execute() async
    func cancel()
}

final class TaskQueue {

    private class AsyncTask<T>: PendingTask {

        let label: String?
        var isCancelled = false

        let continuation: CheckedContinuation<T, Error>?
        let block: () async throws -> T

        init(label: String?, continuation: CheckedContinuation<T, Error>?, block: @escaping () async throws -> T) {
            self.label = label
            self.continuation = continuation
            self.block = block
        }

        func execute() async {
            guard !isCancelled else { return }
            do {
                let result = try await block()
                continuation?.resume(returning: result)
            } catch {
                continuation?.resume(throwing: error)
            }
        }

        func cancel() {
            continuation?.resume(throwing: CancellationError())
        }
    }

    private class StreamTask<T>: PendingTask {
        let label: String?
        var isCancelled = false

        let continuation: AsyncThrowingStream<T, Error>.Continuation
        let block: (AsyncThrowingStream<T, Error>.Continuation) -> Void

        init(label: String?, continuation: AsyncThrowingStream<T, Error>.Continuation, block: @escaping (AsyncThrowingStream<T, Error>.Continuation) -> Void) {
            self.label = label
            self.continuation = continuation
            self.block = block
        }

        func execute() async {
            guard !isCancelled else { return }
            do {
                for try await value in AsyncThrowingStream(T.self, block) {
                    continuation.yield(value)
                }
                continuation.finish()
            } catch {
                continuation.finish(throwing: error)
            }
        }

        func cancel() {
            continuation.finish(throwing: CancellationError())
        }
    }

    private let label: String?

    private var pendingTasksContinuation: AsyncStream<PendingTask>.Continuation
    private var pendingTasks: AsyncStream<PendingTask>
    private var scope: Task<Void,Never>?

    private var isClosed = false

    private func initScope() {
        scope = Task {
            for await pendingTask in pendingTasks {
                guard !Task.isCancelled, !isClosed else {
                    pendingTask.cancel()
                    continue
                }
                await pendingTask.execute()
            }

            for await pendingTask in pendingTasks {
                pendingTask.cancel()
            }
        }
    }

    public init(label: String? = nil){
         self.label = label
         (pendingTasks, pendingTasksContinuation) = AsyncStream.makeStream()
         initScope()
     }

    public func close() {
        guard !isClosed else { return }
        isClosed = true
        scope?.cancel()
        pendingTasksContinuation.finish()
    }

    public func dispatch(label: String? = nil, block: @escaping () async throws -> Void) {
        guard !isClosed else { return }
        pendingTasksContinuation.yield(AsyncTask(label: label, continuation: nil, block: block))
    }

    public func dispatch<T>(label: String? = nil, block: @escaping () async throws -> T) async throws -> T {
        guard !isClosed else { throw CancellationError() }

        var pendingTask: AsyncTask<T>?

        return try await withTaskCancellationHandler {
            try await withCheckedThrowingContinuation { continuation in
                let task = AsyncTask(label: label, continuation: continuation, block: block)
                pendingTask = task
                pendingTasksContinuation.yield(task)
            }
        } onCancel: { [weak pendingTask] in
            pendingTask?.isCancelled = true
        }
    }

    public func dispatchStream<T>(label: String? = nil, block: @escaping (AsyncThrowingStream<T, Error>.Continuation) -> Void) -> AsyncThrowingStream<T, Error> {
        AsyncThrowingStream<T, Error> { typedContinuation in
            guard !isClosed else {
                typedContinuation.finish(throwing: CancellationError())
                return
            }

            let task = StreamTask<T>(label: label, continuation: typedContinuation, block: block)
            pendingTasksContinuation.yield(task)
        }
    }
}

